import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testGetIgnoreEmptyLinesDefaultTrue() {
        // DEFAULT has ignoreEmptyLines = true according to constructor parameter
        assertTrue(CSVFormat.DEFAULT.getIgnoreEmptyLines());
    }

    @Test
    public void testGetIgnoreEmptyLinesFalse() {
        CSVFormat csvFormat = CSVFormat.DEFAULT.withIgnoreEmptyLines(false);
        assertFalse(csvFormat.getIgnoreEmptyLines());
    }

    @Test
    public void testGetIgnoreEmptyLinesTrueAfterFalse() {
        CSVFormat csvFormat = CSVFormat.DEFAULT.withIgnoreEmptyLines(false)
                .withIgnoreEmptyLines(true);
        assertTrue(csvFormat.getIgnoreEmptyLines());
    }

    @Test
    public void testGetIgnoreEmptyLinesOnPredefinedFormats() {
        assertFalse(CSVFormat.EXCEL.getIgnoreEmptyLines());
        assertTrue(CSVFormat.INFORMIX_UNLOAD.getIgnoreEmptyLines());
        assertTrue(CSVFormat.INFORMIX_UNLOAD_CSV.getIgnoreEmptyLines());
        assertFalse(CSVFormat.MYSQL.getIgnoreEmptyLines());
        assertFalse(CSVFormat.RFC4180.getIgnoreEmptyLines());
        assertTrue(CSVFormat.TDF.getIgnoreEmptyLines());
    }
}
